CREATE PROCEDURE [dbo].[spProductBrandCreate] @BrandCode NVARCHAR(50), @BrandName NVARCHAR(100), @Description NVARCHAR(500), @LogoUrl NVARCHAR(500), @CreatedByUserId INT AS BEGIN SET NOCOUNT ON; INSERT INTO [dbo].[ProductBrand] (BrandCode,BrandName,Description,LogoUrl,CreatedByUserId) VALUES (@BrandCode,@BrandName,ISNULL(@Description,N''),ISNULL(@LogoUrl,N''),NULLIF(@CreatedByUserId,0)); SELECT CAST(SCOPE_IDENTITY() AS INT); END;
